// usStateCodes is the bootstrap pool when the local cache is empty and no
// --state was given, so 'random' always returns something live-capable.
var usStateCodes = []string{
	"AL", "AK", "AZ", "AR", "CA", "CO", "CT", "DE", "FL", "GA", "HI", "ID",
	"IL", "IN", "IA", "KS", "KY", "LA", "ME", "MD", "MA", "MI", "MN", "MS",
	"MO", "MT", "NE", "NV", "NH", "NJ", "NM", "NY", "NC", "ND", "OH", "OK",
	"OR", "PA", "RI", "SC", "SD", "TN", "TX", "UT", "VT", "VA", "WA", "WV",
	"WI", "WY",
}

func newNovelRandomCmd(flags *rootFlags) *cobra.Command {
	var flagState string
	var flagCategory string
	cmd := &cobra.Command{
		Use:   "random",
		Short: "Pick a random offbeat attraction, optionally constrained by state or category.",
		Long: strings.Trim(`
Pick a random offbeat attraction for road-trip inspiration. Without flags it
draws from the local cache, sampling a random state live if the cache is empty.
Constrain with --state (two-letter code) and/or --category (see 'category
--list').`, "\n"),
		Example: strings.Trim(`
  roadside-america-pp-cli random
  roadside-america-pp-cli random --state TX
  roadside-america-pp-cli random --state CA --category biggest --json`, "\n"),
		Annotations: map[string]string{"mcp:read-only": "true"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if dryRunOK(flags) {
				fmt.Fprintln(cmd.OutOrStdout(), "would pick a random attraction")
				return nil
			}
			canonCat := ""
			if flagCategory != "" {
				c, ok := roadside.NormalizeCategory(flagCategory)
				if !ok {
					return usageErr(fmt.Errorf("unknown category %q; run 'category --list' to see options", flagCategory))
				}
				canonCat = c
			}

			ctx := cmd.Context()
			s, err := openRoadsideStore(ctx)
			if err != nil {
				return err
			}
			defer s.Close()

			var pool []roadside.Attraction
			note := ""
			if flagState != "" {
				code := strings.ToUpper(strings.TrimSpace(flagState))
				if !roadside.ValidState(code) {
					return usageErr(fmt.Errorf("unknown state/province %q; expected one of: %s", flagState, roadside.StateCodes()))
				}
				pool, note, err = poolForState(ctx, flags, s, code)
				if err != nil {
					return err
				}
			} else {
				pool, _ = loadCachedAttractions(s, 0)
				if len(pool) == 0 && flags.dataSource != "local" {
					code := usStateCodes[rand.IntN(len(usStateCodes))]
					pool, _, err = poolForState(ctx, flags, s, code)
					if err != nil {
						return err
					}
					note = fmt.Sprintf("cache was empty; sampled from %s", roadside.StateName(code))
				}
			}

			if canonCat != "" {
				filtered := make([]roadside.Attraction, 0, len(pool))
				for _, a := range pool {
					if roadside.MatchesCategory(a, canonCat) {
						filtered = append(filtered, a)
					}
				}
				pool = filtered
			}

			view := attractionListView{Query: map[string]any{}}
			if flagState != "" {
				view.Query["state"] = strings.ToUpper(flagState)
			}
			if canonCat != "" {
				view.Query["category"] = canonCat
			}
			if len(pool) == 0 {
				view.Note = "No matching attractions. Try a different --state/--category, or run 'state'/'near' to populate the cache."
				return emitAttractions(cmd, flags, view)
			}
			pick := pool[rand.IntN(len(pool))]
			view.Attractions = []roadside.Attraction{pick}
			view.Note = note
			return emitAttractions(cmd, flags, view)
		},
	}
	cmd.Flags().StringVar(&flagState, "state", "", "Constrain to a two-letter state/province code")
	cmd.Flags().StringVar(&flagCategory, "category", "", "Constrain to a local category (see 'category --list')")
	return cmd
}

// poolForState returns attractions for a state, honoring --data-source.
func poolForState(ctx context.Context, flags *rootFlags, s *storeHandle, code string) ([]roadside.Attraction, string, error) {
	if flags.dataSource == "local" {
		atts, err := stateFromCache(s, code)
		return atts, "", err
	}
	c, err := flags.newClient()
	if err != nil {
		return nil, "", err
	}
	atts, err := fetchStateAttractions(ctx, c, roadside.NormalizeState(code))
	if err != nil {
		if flags.dataSource == "auto" {
			if cached, cerr := stateFromCache(s, code); cerr == nil && len(cached) > 0 {
				return cached, "served from cache (live fetch failed)", nil
			}
		}
		return nil, "", classifyFetchErr(err)
	}
	cacheAttractions(s, atts)
	return atts, "", nil
}
